def _stats(rows: list[dict[str, Any]], name: str) -> dict[str, float]:
    vals = [r[name] for r in rows if r["status"] == "ok"]
    if not vals:
        return {"mean": 0.0, "std": 0.0, "n": 0}
    return {
        "mean": round(mean(vals), 4),
        "std": round(pstdev(vals), 4) if len(vals) > 1 else 0.0,
        "n": len(vals),
    }


